# [doc = " `cmp.lt_s : (Binary{N}, Binary{N}) → Binary{1}` — the **signed** (two's-complement) strict"] # [doc = " order (RFC-0033 §4.1.2, ADR-028, M-767; SMT-LIB `bvslt`), the distinct named counterpart to"] # [doc = " `cmp.lt`'s unsigned-magnitude order on `Binary` (e.g. at `Binary{8}`, `0b1111_1111` is `−1 <"] # [doc = " 0` here but `255 > 0` there). `Binary`-only: balanced ternary is inherently signed, so its D1"] # [doc = " `cmp.lt` order *is* the signed order — a ternary operand refuses with that routing (explicit,"] # [doc = " never a silently duplicated order), as does a float (partial order — ADR-040 §2.4) or any"] # [doc = " width mismatch (never a silent `false`; G2). Width-unbounded, like `cmp.lt`."] fn prim_cmp_lt_s (prim : & str , args : & [& Value]) -> Result < Value , EvalError > { expect_arity (prim , args , 2) ? ; match (args [0] . repr () , args [1] . repr ()) { (Repr :: Binary { width : wa } , Repr :: Binary { width : wb }) => { if wa != wb { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("width mismatch: Binary{{{wa}}} vs Binary{{{wb}}}") , }) ; } let a = as_bits (prim , args [0]) ? ; let b = as_bits (prim , args [1]) ? ; let ord = binary :: cmp_signed (a , b) . ok_or_else (| | EvalError :: PrimType { prim : prim . to_owned () , why : "width mismatch" . to_owned () , }) ? ; bool_result (prim , args , ord == Ordering :: Less) } (Repr :: Ternary { .. } , Repr :: Ternary { .. }) => Err (EvalError :: PrimType { prim : prim . to_owned () , why : "balanced ternary is inherently signed — its cmp.lt order IS the signed order; \
                  use cmp.lt (there is no distinct ternary signed comparison to select)" . to_owned () , }) , _ => Err (EvalError :: PrimType { prim : prim . to_owned () , why : "cmp.lt_s is the Binary two's-complement order (ADR-028): both operands must be \
                  Binary{N} of equal width" . to_owned () , }) , } }

# [doc = " `dense.scale : (Dense{d, s}, Dense{1, s}) → Dense{d, s}` — scalar multiplication (M-890)."] # [doc = " **`Proven`**, carried from the kernel. The factor rides a `Dense{1, s}` value (the pre-Gap-A"] # [doc = " scalar form — see the module note): it must be the **same dtype** as the vector, dim exactly 1,"] # [doc = " and `Exact` (an approximate factor has no defined composition rule — refused, never fabricated);"] # [doc = " the kernel re-checks the factor is finite and on-grid (`ScalarOffGrid`)."] fn prim_dense_scale (prim : & str , args : & [& Value]) -> Result < Value , EvalError > { expect_arity (prim , args , 2) ? ; let space = dense_space_of (prim , args [0]) ? ; let factor = args [1] ; let Repr :: Dense { dim : 1 , dtype } = * factor . repr () else { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("the scale factor must be a Dense{{1, dtype}} scalar (the pre-Gap-A scalar form), \
                 got {:?}" , factor . repr ()) , }) ; } ; if dtype != space . dtype { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("the scale factor dtype {dtype:?} must match the vector dtype {:?} — never a \
                 silent re-round" , space . dtype) , }) ; } if factor . meta () . guarantee () != GuaranteeStrength :: Exact { return Err (EvalError :: ApproxCompositionUnsupported { prim : prim . to_owned () , }) ; } let Payload :: Scalars (xs) = factor . payload () else { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : "the scale factor's payload is not scalar data" . to_owned () , }) ; } ; let [c] = xs . as_slice () else { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("the Dense{{1}} scale factor must carry exactly one element, got {}" , xs . len ()) , }) ; } ; space . scale_value (args [0] , * c) . map_err (| e | map_dense_err (prim , e)) }

# [doc = " Bind the VSA model a `vsa.*` prim dispatches to off its **first operand's** `Repr::Vsa` model"] # [doc = " id + dim (the model anchor); the kernel then enforces every other hypervector operand agrees"] # [doc = " (a model/dim mismatch is an explicit `NotThisModel`/`DimMismatch` refusal, never a coercion)."] # [doc = " A non-`Vsa` first operand, or a model outside the M-892 introduction dispatch set"] # [doc = " (MAP-I / FHRR / BSC), is an explicit [`EvalError::PrimType`] naming the model and the set (G2)."] fn vsa_model_of (prim : & str , v : & Value) -> Result < VsaDispatch , EvalError > { let Repr :: Vsa { model , dim , .. } = v . repr () else { return Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("expected a Vsa hypervector operand, got {:?}" , v . repr ()) , }) ; } ; match model . as_str () { "MAP-I" => Ok (VsaDispatch :: MapI (MapI :: new (* dim))) , "FHRR" => Ok (VsaDispatch :: Fhrr (Fhrr :: new (* dim))) , "BSC" => Ok (VsaDispatch :: Bsc (Bsc :: new (* dim))) , other => Err (EvalError :: PrimType { prim : prim . to_owned () , why : format ! ("model {other:?} is outside the vsa.* prim dispatch set at introduction \
                 (MAP-I, FHRR, BSC — M-892); widening the set is an append-only extension, \
                 never a guessed algebra") , }) , } }
